    int data;
    TreeNode *left;
    TreeNode *right;
};

void preorder(TreeNode *node)
{
    if (node == nullptr) return; // BASE CASE

    cout << node->data << " "; // NODE
    preorder(node->left);        // LEFT
    preorder(node->right);       // RIGHT
}

