#include <iostream>
#include <vector>
#include <stack>

using namespace std;

struct Node {
    int val;
    vector<Node*> children;
    Node(int x) : val(x) {}
};

vector<int> preorder(Node* root)
{
    vector<int> result;
    if (root == nullptr) return result;

    stack<Node*> st;
    st.push(root);

    while (!st.empty())
    {
        Node* node = st.top();
        st.pop();

        result.push_back(node->val);

        for (int i = node->children.size() - 1; i >= 0; i--)
        {
            st.push(node->children[i]);
        }
    }

    return result;
}

int main()
{
    Node* n5 = new Node(5);
    Node* n6 = new Node(6);
    Node* n3 = new Node(3); n3->children = {n5, n6};
    Node* n2 = new Node(2);
    Node* n4 = new Node(4);
    Node* root = new Node(1); root->children = {n3, n2, n4};

    vector<int> result = preorder(root);
    for (int r : result) cout << r << " ";

    return 0;
}

